const dateRange = ctx.var_form1?.date_range || [];
const dateRangeText = dateRange.length === 2
  ? `${dateRange[0]} to ${dateRange[1]}`
  : 'All Time';

const data = ctx.data.objects || [];
const conversionRates = [];
for (let i = 1; i < data.length; i++) {
  const rate = data[i-1].count > 0
    ? ((data[i].count / data[i-1].count) * 100).toFixed(1)
    : 0;
  conversionRates.push(rate);
}

return {
  dataset: { source: ctx.data.objects },
  title: {
    text: `Sales Funnel Analysis - ${dateRangeText}`,
    subtext: "Complete conversion from leads to orders",
    left: "center"
  },
  tooltip: {
    trigger: "item",
    formatter: (params) => {
      const idx = params.dataIndex;
      let result = `${params.name}<br/>`;
      result += `Count: ${params.data.count}<br/>`;
      result += `Value: ¥${(params.data.potential_value || 0).toLocaleString()}<br/>`;
      if (idx > 0 && conversionRates[idx - 1]) {
        result += `Conversion Rate: ${conversionRates[idx - 1]}%`;
      } else if (idx === 0) {
        result += `(Funnel Top)`;
      }
      return result;
    }
  },
  series: [{
    name: "Sales Funnel",
    type: "funnel",
    left: "10%", top: 100, bottom: 60, width: "80%",
    min: 0, max: 100, minSize: "20%", maxSize: "100%",
    sort: "descending", gap: 2,
    label: {
      show: true, position: "inside",
      formatter: (params) => {
        const idx = params.dataIndex;
        let text = `${params.name}\n${params.data.count}`;
        if (idx > 0 && conversionRates[idx - 1]) {
          text += `\n▼ ${conversionRates[idx - 1]}%`;
        }
        return text;
      },
      fontSize: 14, fontWeight: 'bold', color: '#333',
      textBorderColor: '#fff', textBorderWidth: 2
    },
    itemStyle: {
      borderColor: "#fff", borderWidth: 2,
      color: (params) => {
        const colors = ['#5470c6', '#91cc75', '#fac858', '#ee6666'];
        return colors[params.dataIndex % colors.length];
      },
      opacity: 0.85
    },
    emphasis: {
      label: { fontSize: 18, fontWeight: 'bold', color: '#333', textBorderColor: '#fff', textBorderWidth: 3 },
      itemStyle: { opacity: 1 }
    },
    encode: { value: "count", itemName: "stage" }
  }],
  graphic: [{
    type: "text", left: "center", bottom: 20,
    style: { text: "▼ indicates conversion rate from previous stage", fontSize: 12, fill: "#666" }
  }]
}

