  const prevRevenue = data[i-1].monthly_revenue || 0;
  const currRevenue = data[i].monthly_revenue || 0;
  const rate = prevRevenue > 0
    ? (((currRevenue - prevRevenue) / prevRevenue) * 100).toFixed(1)
    : 0;
  growthRates.push(rate);
}

return {
  dataset: { source: data },
  title: {
