var colors = ['#fef3c7','#fde68a','#fcd34d','#f59e0b','#d97706','#92400e'];
var pieData = data.map(function(d, i) {
  return { name: d.name, value: Number(d.value || 0), avg_days: d.avg_days,
    itemStyle: { color: colors[i % colors.length] } };
});
return {
  title: { text: 'Deal Cycle Distribution', subtext: total + ' won deals', left: 'center' },
  tooltip: { trigger: 'item',
    formatter: function(p) { return p.name + '<br/>Deals: ' + p.value + ' (' + p.percent + '%)<br/>Avg: ' + (p.data.avg_days||0) + ' days'; }
  },
  legend: { bottom: 0 },
  series: [{
    type: 'pie', radius: ['40%','70%'], center: ['50%','45%'],
    itemStyle: { borderRadius: 8, borderColor: '#fff', borderWidth: 2 },
    label: { show: true, formatter: function(p) { return p.name + '\n' + p.percent + '%'; }, fontSize: 11 },
    emphasis: { label: { fontSize: 15, fontWeight: 'bold' } },
    data: pieData
  }]
}

var data = ctx.data.objects || [];
return {
  title: { text: 'Monthly Won Deals & Cycle Time', left: 'center' },
  tooltip: { trigger: 'axis',
    formatter: function(params) {
      var r = params[0].axisValue + '<br/>';
      params.forEach(function(i) {
        if (i.seriesName === 'Won Deals') r += i.marker + 'Won: ' + i.value + '<br/>';
        else r += i.marker + 'Avg Cycle: ' + i.value + ' days<br/>';
      });
      return r;
    }
  },
  legend: { bottom: 0 },
  grid: { left: '3%', right: '4%', bottom: 50, top: 60, containLabel: true },
  xAxis: { type: 'category', data: data.map(function(d){return d.month}), axisLabel: { rotate: 45, fontSize: 10 } },
  yAxis: [
    { type: 'value', name: 'Won Deals' },
    { type: 'value', name: 'Avg Days', position: 'right' }
  ],
  series: [
    { name: 'Won Deals', type: 'bar', data: data.map(function(d){ return Number(d.won_count); }),
      itemStyle: { color: '#22c55e', borderRadius: [4,4,0,0] },
      label: { show: true, position: 'top', fontSize: 9 } },
    { name: 'Avg Cycle', type: 'line', yAxisIndex: 1, data: data.map(function(d){ return Number(d.avg_days); }),
